from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch
from elasticsearch.exceptions import ElasticsearchException
import os
import re
from functools import wraps
import time
from collections import defaultdict
import threading

app = Flask(__name__)

ES_HOST = os.environ.get('ELASTICSEARCH_HOST', 'localhost')
ES_PORT = int(os.environ.get('ELASTICSEARCH_PORT', 9200))
ES_INDEX = os.environ.get('ELASTICSEARCH_INDEX', 'products')
ES_USER = os.environ.get('ELASTICSEARCH_USER', '')
ES_PASSWORD = os.environ.get('ELASTICSEARCH_PASSWORD', '')

if ES_USER and ES_PASSWORD:
    es = Elasticsearch(
        [{'host': ES_HOST, 'port': ES_PORT, 'scheme': 'https'}],
        basic_auth=(ES_USER, ES_PASSWORD),
        verify_certs=True,
        ca_certs=os.environ.get('ES_CA_CERTS'),
        timeout=30,
        max_retries=3,
        retry_on_timeout=True
    )
else:
    es = Elasticsearch(
        [{'host': ES_HOST, 'port': ES_PORT, 'scheme': 'http'}],
        timeout=30,
        max_retries=3,
        retry_on_timeout=True
    )

rate_limit_storage = defaultdict(list)
rate_limit_lock = threading.Lock()

RATE_LIMIT_REQUESTS = int(os.environ.get('RATE_LIMIT_REQUESTS', 100))
RATE_LIMIT_WINDOW = int(os.environ.get('RATE_LIMIT_WINDOW', 60))

def get_client_ip():
    if request.headers.get('X-Forwarded-For'):
        return request.headers.get('X-Forwarded-For').split(',')[0].strip()
    elif request.headers.get('X-Real-IP'):
        return request.headers.get('X-Real-IP')
    return request.remote_addr

def rate_limit(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        client_ip = get_client_ip()
        current_time = time.time()
        
        with rate_limit_lock:
            requests = rate_limit_storage[client_ip]
            requests = [req_time for req_time in requests if current_time - req_time < RATE_LIMIT_WINDOW]
            
            if len(requests) >= RATE_LIMIT_REQUESTS:
                return jsonify({
                    'error': 'Rate limit exceeded',
                    'message': f'Maximum {RATE_LIMIT_REQUESTS} requests per {RATE_LIMIT_WINDOW} seconds'
                }), 429
            
            requests.append(current_time)
            rate_limit_storage[client_ip] = requests
        
        return f(*args, **kwargs)
    return decorated_function

def sanitize_query(query):
    if not query or not isinstance(query, str):
        return ''
    
    query = query.strip()
    
    if len(query) > 200:
        query = query[:200]
    
    dangerous_chars = ['\\', '/', '(', ')', '{', '}', '[', ']', '^', '~', '?', ':', '"', '<', '>', '|']
    for char in dangerous_chars:
        query = query.replace(char, ' ')
    
    query = re.sub(r'\s+', ' ', query).strip()
    
    return query

def validate_pagination(page, size):
    try:
        page = int(page)
        size = int(size)
    except (ValueError, TypeError):
        return 1, 10
    
    page = max(1, min(page, 1000))
    size = max(1, min(size, 100))
    
    return page, size

@app.route('/api/search', methods=['GET'])
@rate_limit
def search_products():
    try:
        query = request.args.get('q', '')
        page = request.args.get('page', 1)
        size = request.args.get('size', 10)
        
        sanitized_query = sanitize_query(query)
        
        if not sanitized_query:
            return jsonify({
                'error': 'Invalid query',
                'message': 'Search query is required and must be valid'
            }), 400
        
        page, size = validate_pagination(page, size)
        from_index = (page - 1) * size
        
        search_body = {
            'query': {
                'bool': {
                    'should': [
                        {
                            'multi_match': {
                                'query': sanitized_query,
                                'fields': ['name^3', 'description^2', 'category', 'tags'],
                                'type': 'best_fields',
                                'fuzziness': 'AUTO',
                                'operator': 'or'
                            }
                        },
                        {
                            'match_phrase': {
                                'name': {
                                    'query': sanitized_query,
                                    'boost': 5
                                }
                            }
                        }
                    ],
                    'minimum_should_match': 1
                }
            },
            'from': from_index,
            'size': size,
            '_source': ['id', 'name', 'description', 'price', 'category', 'image_url', 'in_stock'],
            'highlight': {
                'fields': {
                    'name': {},
                    'description': {}
                },
                'pre_tags': ['<mark>'],
                'post_tags': ['</mark>']
            }
        }
        
        response = es.search(index=ES_INDEX, body=search_body)
        
        hits = response['hits']['hits']
        total = response['hits']['total']['value']
        
        products = []
        for hit in hits:
            product = hit['_source']
            product['score'] = hit['_score']
            
            if 'highlight' in hit:
                product['highlight'] = hit['highlight']
            
            products.append(product)
        
        result = {
            'query': sanitized_query,
            'total': total,
            'page': page,
            'size': size,
            'total_pages': (total + size - 1) // size,
            'products': products
        }
        
        return jsonify(result), 200
        
    except ElasticsearchException as e:
        app.logger.error(f'Elasticsearch error: {str(e)}')
        return jsonify({
            'error': 'Search service error',
            'message': 'Unable to process search request at this time'
        }), 503
        
    except Exception as e:
        app.logger.error(f'Unexpected error: {str(e)}')
        return jsonify({
            'error': 'Internal server error',
            'message': 'An unexpected error occurred'
        }), 500

@app.route('/api/health', methods=['GET'])
def health_check():
    try:
        es.cluster.health()
        return jsonify({'status': 'healthy', 'elasticsearch': 'connected'}), 200
    except Exception as e:
        return jsonify({'status': 'unhealthy', 'elasticsearch': 'disconnected'}), 503

@app.errorhandler(404)
def not_found(e):
    return jsonify({'error': 'Not found', 'message': 'The requested resource was not found'}), 404

@app.errorhandler(405)
def method_not_allowed(e):
    return jsonify({'error': 'Method not allowed', 'message': 'The HTTP method is not allowed for this endpoint'}), 405

@app.errorhandler(500)
def internal_error(e):
    return jsonify({'error': 'Internal server error', 'message': 'An unexpected error occurred'}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)